function active$FormTSDepartment(f) {f.add_onResponseComplete(on$FormTSDepartment$ResponseComplete);}
function close$FormTSDepartment(f) {try {f.remove_onResponseComplete(on$FormTSDepartment$ResponseComplete)} catch (ex) {}}
function on$FormTSDepartment$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_bp');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
